// Scroll ALL resources from Qdrant with pagination
let allPoints = [];
let offset = null;
do {
  const body = { limit: 100, with_payload: { include: ['metadata'] } };
  if (offset) body.offset = offset;
  const response = await this.helpers.httpRequest({
    method: 'POST',
    url: 'http://qdrant:6333/collections/k8s/points/scroll',
    body,
    json: true
  });
  const page = response.result?.points || [];
  allPoints.push(...page);
  offset = response.result?.next_page_offset || null;
} while (offset);

if (allPoints.length === 0) return 'No Kubernetes resources found in the vector database.';

// Parse all resources
const resources = allPoints.map(p => {
  const m = p.payload?.metadata || {};
  return {
    kind: m.kind || '?',
    name: m.name || '?',
    namespace: m.namespace || 'cluster-scoped',
    labels: m.labels || '{}',
    spec: m.spec_summary || '-'
  };
});

// === SECTION 1: Namespace summary (total resources per namespace) ===
const byNsAll = {};
for (const r of resources) {
  if (!byNsAll[r.namespace]) byNsAll[r.namespace] = {};
  byNsAll[r.namespace][r.kind] = (byNsAll[r.namespace][r.kind] || 0) + 1;
}
const lines = [`CLUSTER INVENTORY — ${resources.length} resources total`, ''];
lines.push('NAMESPACE SUMMARY:');
lines.push('| Namespace | Total | Pod | Deployment | Service | ConfigMap | Secret | ReplicaSet | StatefulSet | DaemonSet | PVC | Other |');
for (const ns of Object.keys(byNsAll).sort()) {
  const k = byNsAll[ns];
  const total = Object.values(k).reduce((a, b) => a + b, 0);
  const known = ['Pod','Deployment','Service','ConfigMap','Secret','ReplicaSet','StatefulSet','DaemonSet','PVC'];
  const other = Object.entries(k).filter(([t]) => !known.includes(t)).reduce((a, [, c]) => a + c, 0);
  lines.push(`| ${ns} | ${total} | ${known.map(t => k[t] || 0).join(' | ')} | ${other} |`);
}

// === SECTION 2: Detailed breakdown by kind ===
lines.push('');
lines.push('DETAILED BREAKDOWN BY KIND:');
const byKind = {};
for (const r of resources) {
  if (!byKind[r.kind]) byKind[r.kind] = [];
  byKind[r.kind].push(r);
}
for (const kind of Object.keys(byKind).sort()) {
  const items = byKind[kind];
  const byNs = {};
  for (const item of items) {
    if (!byNs[item.namespace]) byNs[item.namespace] = [];
    byNs[item.namespace].push(item);
  }
  lines.push(`${kind} (${items.length} total):`);
  for (const ns of Object.keys(byNs).sort()) {
    const nsItems = byNs[ns];
    lines.push(`  ${ns} (${nsItems.length}):`);
    for (const item of nsItems) {
      lines.push(`    - ${item.name} [${item.spec}]`);
    }
  }
}

return lines.join('\n');
